    "file": "src/Components/Web/src/Forms/DisplayName.cs",
    "line": 46,
    "severity": "high",
    "description": "Hot reload metadata changes are not reflected without expression reference change. The component checks 'if (For != _previousFieldAccessor)' before recalculating the display name. When hot reload occurs and attributes (like [Display(Name=...)]) are added/removed from a property, ExpressionMemberAccessor clears its caches. However, if the same expression object is passed on the next render (which can happen in Blazor), the component skips GetDisplayName and won't see the updated metadata. This results in stale display names after attribute changes during development.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -44,16 +44,16 @@ namespace Microsoft.AspNetCore.Components.Forms;
             throw new InvalidOperationException($"{GetType()} requires a value for the " +
                 $"{nameof(For)} parameter.");
         }

-        // Only recalculate if the expression changed
-        if (For != _previousFieldAccessor)
+        // Always recalculate to respect metadata changes (e.g., from hot reload)
+        var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
+
+        if (newDisplayName != _displayName)
         {
-            var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
-
-            if (newDisplayName != _displayName)
-            {
-                _displayName = newDisplayName;
-                _renderHandle.Render(BuildRenderTree);
-            }
+            _displayName = newDisplayName;
+            _renderHandle.Render(BuildRenderTree);
+        }

+        // Track the previous expression for detecting future changes
+        if (For != _previousFieldAccessor)
         {
             _previousFieldAccessor = For;
         }
"
  },
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 15,
    "severity": "high",
    "description": "Unbounded memory leak in _memberInfoCache due to Expression object reuse pattern. Expression<Func<TValue>> objects are used as cache keys, but in Blazor, each component render typically creates new expression instances (e.g., 'For="@(() => model.Property)"'). Logically identical expressions create different cache entries because Expression objects use reference equality, not value equality. This causes the cache to grow unbounded over the application's lifetime as components render repeatedly, accumulating thousands of entries for the same properties.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -27,43 +27,30 @@ namespace Microsoft.AspNetCore.Components.Forms;

     private static MemberInfo GetMemberInfo<TValue>(Expression<Func<TValue>> accessor)
     {
         ArgumentNullException.ThrowIfNull(accessor);

-        return _memberInfoCache.GetOrAdd(accessor, static expr =>
+        // Extract and return MemberInfo without caching the expression object.
+        // Expression objects are not reused in Blazor (new instances on each render),
+        // so caching them causes unbounded memory growth. MemberInfo itself is cached
+        // effectively by GetDisplayName, which is the more useful cache.
+        var lambdaExpression = (LambdaExpression)accessor;
+        var accessorBody = lambdaExpression.Body;
+
+        if (accessorBody is UnaryExpression unaryExpression
+            && unaryExpression.NodeType == ExpressionType.Convert
+            && unaryExpression.Type == typeof(object))
         {
-            var lambdaExpression = (LambdaExpression)expr;
-            var accessorBody = lambdaExpression.Body;
-
-            if (accessorBody is UnaryExpression unaryExpression
-                && unaryExpression.NodeType == ExpressionType.Convert
-                && unaryExpression.Type == typeof(object))
-            {
-                accessorBody = unaryExpression.Operand;
-            }
-
-            if (accessorBody is not MemberExpression memberExpression)
-            {
-                throw new ArgumentException(
-                    $"The provided expression contains a {accessorBody.GetType().Name} which is not supported. " +
-                    $"Only simple member accessors (fields, properties) of an object are supported.");
-            }
-
-            return memberExpression.Member;
-        });
+            accessorBody = unaryExpression.Operand;
+        }
+
+        if (accessorBody is not MemberExpression memberExpression)
+        {
+            throw new ArgumentException(
+                $"The provided expression contains a {accessorBody.GetType().Name} which is not supported. " +
+                $"Only simple member accessors (fields, properties) of an object are supported.");
+        }
+
+        return memberExpression.Member;
     }
"
  }
]

